return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook MTR Upload1')[idx]?.json || {};
  const out = j.output || j.data?.output || j.data || j.result?.output || j.result || j;
  return {
    json: {
      mtr_id: j.mtr_id || original.mtr_id || original.mtrId || '',
      output: out,
    }
  };
});

return items.map((item, idx) => {
  const j = item.json || {};
  const text = (j.content && j.content[0] && j.content[0].text) || '';
  let obj = {};
  try {
    obj = JSON.parse(text.trim());
  } catch (e) {
    const a = text.indexOf('{');
    const b = text.lastIndexOf('}');
    if (a >= 0 && b > a) {
      try { obj = JSON.parse(text.slice(a, b + 1)); } catch (_) {}
    }
  }
  return {
    json: {
      ...j,
      output: obj,
    },
    binary: item.binary
  };
});

const promises = items.map(async (item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || {};
  let pdf = j.file_content_base64 || original.file_content_base64 || '';

  if (!pdf) {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(idx, 'data0');
      pdf = buf.toString('base64');
    } catch (e) {}
  }

  const prompt = (j.selected_prompt || j.extraction_system_message || '').toString().trim();
  if (!pdf || !prompt) {
    throw new Error('Missing pdf or prompt');
  }

  return {
    json: {
      ...original,
      ...j,
      file_content_base64: original.file_content_base64 || j.file_content_base64,
      claude_extract_body: {
        model: 'claude-sonnet-4-6',
        max_tokens: 8192,
        messages: [
          {
            role: 'user',
            content: [
              { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdf } },
              { type: 'text', text: prompt }
            ]
          }
        ]
      }
    }
  };
});

return Promise.all(promises);

return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || {};
  const text = (j.content && j.content[0] && j.content[0].text) || '';
  let obj = {};
  try {
    obj = JSON.parse(text.trim());
  } catch (e) {
    const a = text.indexOf('{');
    const b = text.lastIndexOf('}');
    if (a >= 0 && b > a) {
      try { obj = JSON.parse(text.slice(a, b + 1)); } catch (_) {}
    }
  }
  return {
    json: {
      ...original,
      ...j,
      output: obj,
    }
  };
});

return items.map(item => {
  const j = item.json || {};
  let prompt = (j.selected_prompt || j.extraction_system_message || '').toString().trim();
  let prompt_missing = false;
  if (!prompt) {
    prompt_missing = true;
    // Minimal safe fallback to avoid hard stop
    prompt = 'Return {}';
  }
  return { 
    json: { ...j, selected_prompt: prompt, extraction_system_message: prompt, prompt_missing }
  };
});

return items.map((item, idx) => {
  const auth = $items("Auth to Odoo1")[0]?.json || {};
  // Keep payload fields authoritative (db_name, odoo_url, etc.)
  return { json: { ...auth, ...item.json } };
});

return items.flatMap(item => {
  const j = item.json || {};
  const heat = (j.heat_number || '').toString().trim();
  const batch = (j.batch_number || '').toString().trim();
  const mtrId = (j.mtr_id || '').toString().trim();

  if (!heat) {
    // Skip records without heat_number (Odoo requires it)
    j.validation_warning = 'Missing heat_number';
    return [];
  }

  if (batch) {
    j.batch_number = batch;
  }

  const badTokens = ['fewf', 'ferf', 'ref', 'fre'];
  const lowered = JSON.stringify({
    manufacturer: j.manufacturer,
    grade: j.grade,
    certificate_number: j.certificate_number,
  }).toLowerCase();
  if (badTokens.some(t => lowered.includes(t))) {
    // Mark garbage but don't block
    j.validation_warning = 'Garbage tokens detected';
  }

  return [{ json: j }];
});

return items.flatMap((item, idx) => {
  const src = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook MTR Upload1')[idx]?.json || {};
  const normalizeId = (v) => {
    if (v === undefined || v === null) return '';
    if (typeof v === 'number') return String(v);
    const s = String(v).trim();
    if (!s) return '';
    const m = s.match(/\d+/);
    return m ? m[0] : s;
  };
  const baseMtrId = normalizeId(src.mtr_id || src.mtrId || original.mtr_id || original.mtrId || '');

  const parseMaybeJson = (v) => {
    if (!v) return null;
    if (typeof v === 'object') return v;
    if (typeof v !== 'string') return null;
    const s = v.trim();
    try {
      return JSON.parse(s);
    } catch (_) {
      const a = s.indexOf('{');
      const b = s.lastIndexOf('}');
      if (a >= 0 && b > a) {
        try { return JSON.parse(s.slice(a, b + 1)); } catch (__) {}
      }
      return null;
    }
  };

  // AI node output can come in different wrappers
  const parsedOutput = parseMaybeJson(src.output);
  const parsedText = parseMaybeJson(src.text);
  const root =
    (src.output && (src.output.certificateHeader || src.output.materialTestRecords)) ? src.output :
    (src.certificateHeader || src.materialTestRecords) ? src :
    (parsedOutput && parsedOutput.output && (parsedOutput.output.certificateHeader || parsedOutput.output.materialTestRecords)) ? parsedOutput.output :
    (parsedOutput && (parsedOutput.certificateHeader || parsedOutput.materialTestRecords)) ? parsedOutput :
    (parsedText && parsedText.output && (parsedText.output.certificateHeader || parsedText.output.materialTestRecords)) ? parsedText.output :
    (parsedText && (parsedText.certificateHeader || parsedText.materialTestRecords)) ? parsedText :
    (src.data && src.data.output && (src.data.output.certificateHeader || src.data.output.materialTestRecords)) ? src.data.output :
    (src.data && (src.data.certificateHeader || src.data.materialTestRecords)) ? src.data :
    src;

  const records =
    (Array.isArray(root.materialTestRecords) && root.materialTestRecords) ||
    (Array.isArray(root.material_test_records) && root.material_test_records) ||
    [];

  const misc = root.miscellaneous || root.misc || {};
  const hdr = root.certificateHeader || root.header || {};

  const asStr = (v) => (v === undefined || v === null ? '' : String(v).trim());
  const normalizeNumberString = (raw) => {
    if (raw === undefined || raw === null) return '';
    let s = String(raw).trim();
    if (!s) return '';

    // If it uses comma as decimal separator (e.g. 0,05), convert to dot.
    if (s.includes(',') && !s.includes('.')) {
      const m = s.match(/^\d{1,3},\d{1,6}$/);
      if (m) {
        s = s.replace(',', '.');
      } else {
        // Otherwise treat commas as thousands separators
        s = s.replace(/,/g, '');
      }
    } else {
      // Remove thousands separators like 1,234.56
      s = s.replace(/,/g, '');
    }

    return s;
  };

  const asNum = (v) => {
    if (v === undefined || v === null || v === '') return null;
    if (typeof v === 'number') return Number.isFinite(v) ? v : null;
    const cleaned = normalizeNumberString(v);
    if (!cleaned) return null;
    const m = cleaned.match(/-?\d+(?:\.\d+)?/);
    return m ? Number(m[0]) : null;
  };

  const asChemNum = (v) => {
    if (v === undefined || v === null || v === '') return null;
    if (typeof v === 'number') return Number.isFinite(v) ? v : null;
    const cleaned = normalizeNumberString(v);
    if (!cleaned) return null;
    const m = cleaned.match(/-?\d+(?:\.\d+)?/);
    return m ? Number(m[0]) : null;
  };

  const normalizeDate = (v) => {
    if (v === undefined || v === null) return '';
    const s = String(v).trim();
    if (!s) return '';
    // Remove time if present (e.g. "2024-01-02 00:00:00" or ISO)
    const tSplit = s.replace('T', ' ').split(' ');
    const datePart = tSplit[0];

    if (/^\d{4}-\d{2}-\d{2}$/.test(datePart)) return datePart;

    let m = datePart.match(/^(\d{4})[\/.-](\d{1,2})[\/.-](\d{1,2})$/);
    if (m) {
      const y = m[1];
      const mm = m[2].padStart(2, '0');
      const dd = m[3].padStart(2, '0');
      return `${y}-${mm}-${dd}`;
    }

    // m/d/yyyy (US) or d/m/yyyy. If ambiguous, assume US (m/d/yyyy)
    m = datePart.match(/^(\d{1,2})[\/.-](\d{1,2})[\/.-](\d{4})$/);
    if (m) {
      const a = Number(m[1]);
      const b = Number(m[2]);
      const y = m[3];
      let mm, dd;
      if (a > 12 && b <= 12) {
        dd = a; mm = b;
      } else {
        mm = a; dd = b;
      }
      const mm2 = String(mm).padStart(2, '0');
      const dd2 = String(dd).padStart(2, '0');
      return `${y}-${mm2}-${dd2}`;
    }

    return datePart;
  };

  const preserveGrade = (g) => {
    if (g === undefined || g === null) return '';
    const t = String(g).replace(/\s+/g, ' ').trim();
    return t;
  };

  const isBadGrade = (g) => false;

  const pick = (obj, keys) => {
    for (const k of keys) {
      if (obj && obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== '') return obj[k];
    }
    return '';
  };

  const splitHeats = (h) => {
    const s0 = String(h || '').trim();
    if (s0 === '') return [''];

    // Normalize explicit separators only (avoid splitting on whitespace)
    const s = s0.replace(/\band\b/gi, ',').replace(/[;\/\n&]+/g, ',');
    const parts = s.split(',').map(p => p.trim()).filter(Boolean);
    return parts.length ? parts : [s0];
  };

  const mapRec = (rec) => {
    const chem = rec.chemicalComposition || rec.chemical || rec.chemistry || {};
    const mech = rec.mechanicalProperties || rec.mechanical || {};
    const ssab = rec.ssab || rec.ssab_fields || rec.ssabFields || {};
    const charpy = rec.charpyImpactTest || rec.charpy || rec.charpy_impact || {};
    const algoma = rec.algoma || rec.algoma_fields || rec.algomaFields || {};
    const phys = rec.physicalProperties || rec.physical || {};

    const heat = asStr(
      pick(rec, ['heatNumber', 'heat_number', 'heatNo', 'heat_no', 'heat', 'heat#', 'heatId', 'heat_id'])
    );

    const batch = asStr(
      pick(rec, [
        'batchNumber', 'batch_number', 'batchNo', 'batch_no',
        'bundleNumber', 'bundleNo', 'bundle_no', 'bundle',
        'tag', 'tagNumber', 'tag_no', 'tag#',
        'lot', 'lotNumber', 'lot_no',
        'coil', 'coilNumber', 'coil_no'
      ])
    );

    const testNo = asStr(pick(rec, ['testNumber','test_number','testNo','test_no']));
    let batchFinal = batch;
    if (!batchFinal && testNo && /^DA\d+/i.test(testNo)) {
      batchFinal = testNo;
    }

    const slab = asStr(
      pick(rec, ['slabNumber', 'slab_number', 'slabNo', 'slab_no', 'slab']) ||
      pick(hdr, ['slabNumber', 'slab_number', 'slabNo', 'slab_no', 'slab'])
    );

    return {
      normalized_root_keys: Object.keys(root || {}),
      heat_number: heat,
      batch_number: batchFinal,
      slab_number: slab,
      grade: (() => {
        const hdrGrade = preserveGrade(pick(hdr, ['grade', 'materialGrade', 'material_grade', 'material', 'specification']));
        const recGrade = preserveGrade(pick(rec, ['grade', 'materialGrade', 'material_grade', 'material', 'specification']));
        const miscSpec = preserveGrade(pick(misc, ['standard', 'specification', 'specifications']));

        const candidates = [hdrGrade, recGrade, miscSpec].filter(v => v && !isBadGrade(v));
        return candidates[0] || '';
      })(),
      manufacturer: (() => {
        let val = asStr(pick(hdr, ['manufacturer', 'mill', 'supplier', 'issuedFrom', 'issued_from']));
        if (!val) {
          val = asStr(src.manufacturer_hint || src.manufacturer_name || src.detected_manufacturer || '');
        }
        return val;
      })(),
      certificate_number: asStr(pick(hdr, ['certificateNumber', 'certificate_number', 'certNumber', 'certNo', 'certificateNo', 'testReference', 'test_reference', 'reportNumber'])),
      certificate_date: normalizeDate(pick(hdr, ['certificateDate', 'certificate_date', 'date', 'issueDate', 'issuedDate', 'reportDate'])),
      country_of_melt: asStr(pick(misc, ['countryOfMeltPour', 'country_of_melt', 'meltCountry', 'countryOfMelt'])),
      country_of_manufacture: asStr(pick(misc, ['countryOfManufacture', 'country_of_manufacture', 'countryOfOrigin', 'origin', 'manufacturedIn', 'madeIn']) || ''),
      c: asChemNum(pick(chem, ['C', 'c'])),
      mn: asNum(pick(chem, ['Mn', 'mn'])),
      si: asNum(pick(chem, ['Si', 'si'])),
      p: asChemNum(pick(chem, ['P', 'p'])),
      s: asChemNum(pick(chem, ['S', 's'])),
      b: asChemNum(pick(chem, ['B', 'b', 'boron', 'Boron'])),
      v: asChemNum(pick(chem, ['V', 'v', 'vanadium', 'Vanadium'])),
      nb: asChemNum(pick(chem, ['Nb', 'nb', 'niobium', 'Niobium'])),
      ti: asChemNum(pick(chem, ['Ti', 'ti', 'titanium', 'Titanium'])),
      al: asChemNum(pick(chem, ['Al', 'al', 'AL', 'A1', 'A1*', 'Al*', 'aluminum', 'aluminium'])),
      cu: asNum(pick(chem, ['Cu', 'cu'])),
      ni: asNum(pick(chem, ['Ni', 'ni'])),
      cr: asNum(pick(chem, ['Cr', 'cr'])),
      mo: asNum(pick(chem, ['Mo', 'mo'])),
      yield_strength: asNum(pick(mech, ['yieldStrength', 'yield_strength'])),
      tensile_strength: asNum(pick(mech, ['tensileStrength', 'tensile_strength'])),
      elongation: asNum(pick(mech, ['elongation'])),
      reduction_area: asNum(pick(mech, ['reductionArea', 'reduction_area'])),
      hardness: asNum(pick(mech, ['hardness'])),
      impact_charpy: asNum(pick(mech, ['impactCharpy', 'impact_charpy', 'impactCharpyAverage', 'impact_charpy_average'])) || 
        asNum(pick(charpy, ['average', 'avg', 'impact_average'])),
      plate_dimension: asStr(
        pick(mech, ['plateDimension', 'plate_dimension', 'plate dimension', 'Plate dimension', 'Plate_dimension', 'plate_dimensions', 'dimensions', 'dimension']) ||
        pick(phys, ['plateDimension', 'plate_dimension', 'dimensions', 'dimension', 'size'])
      ),
      direction: asStr(
        pick(mech, ['direction', 'dir', 'Dir', 'testDirection', 'test_direction']) ||
        pick(charpy, ['direction', 'dir', 'testDirection', 'test_direction'])
      ),

      impact_test_temp: asNum(
        pick(charpy, ['testTemperature', 'test_temperature', 'temperature', 'temp']) ||
        pick(mech, ['impact_test_temp', 'impactTestTemp'])
      ),
      impact_specimen_1: asNum(pick(charpy, ['specimen1', 'impact1', 'e1', 'energy1', 'result1'])),
      impact_specimen_2: asNum(pick(charpy, ['specimen2', 'impact2', 'e2', 'energy2', 'result2'])),
      impact_specimen_3: asNum(pick(charpy, ['specimen3', 'impact3', 'e3', 'energy3', 'result3'])),
      impact_average: asNum(pick(charpy, ['average', 'avg', 'impact_average']) || pick(mech, ['impactCharpy', 'impact_average'])),
      impact_coupon_size: asStr(pick(charpy, ['testSize', 'size', 'specimenSize'])),
      algoma_gauge: asStr(pick(algoma, ['gauge'])),
      algoma_cond: asStr(pick(algoma, ['cond','condition'])),
      algoma_dir: asStr(pick(algoma, ['dir','direction'])),
      algoma_loc: asStr(pick(algoma, ['loc','location'])),
      algoma_srce: asStr(pick(algoma, ['srce','source'])),
      algoma_lab: asStr(pick(algoma, ['lab','laboratory'])),
      algoma_meth: asStr(pick(algoma, ['meth','method'])),
      algoma_smpl_depth: asNum(pick(algoma, ['smpl_depth','sample_depth'])),
      algoma_elongation_scale: asStr(pick(algoma, ['elongation_scale','el_scale'])),
      algoma_roa: asNum(pick(algoma, ['roa','reduction_area'])),
      gauge: asStr(pick(mech, ['gauge']) || pick(phys, ['diameter'])),
      cond: asStr(pick(mech, ['cond', 'condition', 'condn'])),
      dir: asStr(pick(mech, ['dir', 'direction'])),
      loc: asStr(pick(mech, ['loc', 'location'])),
      srce: asStr(pick(mech, ['srce', 'SRCE', 'source'])),
      lab: asStr(pick(mech, ['lab', 'laboratory'])),
      meth: asStr(pick(mech, ['meth', 'method'])),
      smpl_depth: asNum(pick(mech, ['smpl_depth', 'smpldepth', 'sample_depth', 'sampleDepth'])),
      elongation_scale: asStr(pick(mech, ['elongation_scale', 'elongationScale', 'el_scale', 'el_scale_in', 'el_scale_inch', 'elongation_scale_in'])),
      roa: asNum(pick(mech, ['roa', 'reduction_area', 'reductionArea'])),
      ssab: ssab,
      charpy: charpy,
    };
  };

  const baseRecords = records.length ? records : [];
  if (!baseRecords.length) return [];

  const mappedRecords = baseRecords.map(mapRec);
  const expandedRecords = mappedRecords.flatMap((r) => {
    const heats = splitHeats(r.heat_number);
    if (heats.length <= 1) return [r];
    return heats.map(h => ({ ...r, heat_number: h }));
  });

  const mergedMap = new Map();
  for (const r of expandedRecords) {
    const key = (r.heat_number || '').toString().trim();
    if (!key) continue;
    if (!mergedMap.has(key)) {
      mergedMap.set(key, { ...r, _batch_set: new Set() });
    }
    const entry = mergedMap.get(key);
    const b = (r.batch_number || '').toString().trim();
    if (b) entry._batch_set.add(b);
  }
  const mergedRecordsFinal = Array.from(mergedMap.values()).map(r => {
    const batches = Array.from(r._batch_set);
    const batch_number = batches.length ? batches.join(', ') : (r.batch_number || '');
    const { _batch_set, ...rest } = r;
    return { ...rest, batch_number };
  });

  // Update pending record for first heat, create new for others
  if (baseMtrId) {
    return mergedRecordsFinal.map((r, idx) => ({
      json: {
        ...src,
        ...r,
        heat_number: (r.heat_number || src.heat_number || '').toString().trim(),
        mtr_id: idx === 0 ? baseMtrId : '',
        force_create: idx > 0,
      },
    }));
  }

  return mergedRecordsFinal
    .filter(r => (r.heat_number || '').toString().trim() !== '')
    .map((r, idx) => ({
      json: {
        ...src,
        ...r,
        heat_number: (r.heat_number || src.heat_number || '').toString().trim(),
        mtr_id: idx === 0 ? (baseMtrId || '') : '',
        force_create: idx > 0,
      },
    }));
});

return items.map((item, idx) => {
  const j = item.json;
  const uid = j.result;
  const dbName = (j.db_name || j.database || 'brannon').toString().trim();
  if (!dbName) throw new Error('Missing database/db_name for Odoo upsert');
  if (!uid) throw new Error(`Odoo authentication failed. uid was: ${uid}`);
  const heat = (j.heat_number || '').toString().trim();
  if (!heat) {
    throw new Error(`Missing heat_number before upsert. Keys: ${Object.keys(j).join(', ')}`);
  }
  return {
    json: {
      ...j,
      db_name: dbName,
      rpc_url: j.rpc_url || `${j.odoo_url}/jsonrpc`,
      upsert_body: {
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'object',
          method: 'execute_kw',
          args: [
            dbName,
            uid,
            j.odoo_password,
            'mtr.data',
            'upsert_from_payload',
            [{
              mtr_id: j.mtr_id,
              heat_number: heat,
              batch_number: j.batch_number,
              force_create: j.force_create,
              grade: j.grade,
              manufacturer: j.manufacturer,
              certificate_number: j.certificate_number,
              certificate_date: j.certificate_date,
              slab_number: j.slab_number,
              c: j.c,
              mn: j.mn,
              si: j.si,
              p: j.p,
              s: j.s,
              b: j.b,
              v: j.v,
              nb: j.nb,
              ti: j.ti,
              al: j.al,
              cu: j.cu,
              ni: j.ni,
              cr: j.cr,
              mo: j.mo,
              yield_strength: j.yield_strength,
              tensile_strength: j.tensile_strength,
              elongation: j.elongation,
              reduction_area: j.reduction_area,
              hardness: j.hardness,
              impact_charpy: j.impact_charpy,
              plate_dimension: j.plate_dimension,
              direction: j.direction,
              impact_test_temp: j.impact_test_temp,
              impact_coupon_size: j.impact_coupon_size,
              impact_specimen_1: j.impact_specimen_1,
              impact_specimen_2: j.impact_specimen_2,
              impact_specimen_3: j.impact_specimen_3,
              impact_average: j.impact_average,
              country_of_melt: j.country_of_melt,
              country_of_manufacture: j.country_of_manufacture,
              source_file: j.source_file,
            }],
          ],
        },
        id: 2,
      },
    },
  };
});

return items.map((item, idx) => {
  const j = item.json;
  const dbName = (j.db_name || j.database || '').toString().trim();
  if (!dbName) throw new Error('Missing database/db_name for Odoo auth');
  return {
    json: {
      ...j,
      db_name: dbName,
      rpc_url: `${j.odoo_url}/jsonrpc`,
      auth_body: {
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'common',
          method: 'authenticate',
          args: [dbName, j.odoo_login, j.odoo_password, {}],
        },
        id: 1,
      },
    },
  };
});

return items.map((item) => {
  const root = item.json || {};
  const body = root.body || {};
  const data = root.data || {};

  const fileBase64 =
    root.file_content_base64 ||
    body.file_content_base64 ||
    data.file_content_base64 ||
    root.file_data ||
    body.file_data ||
    data.file_data;

  const mtrId =
    root.mtr_id ||
    body.mtr_id ||
    data.mtr_id ||
    root.mtrId ||
    body.mtrId ||
    data.mtrId;

  const normalizeId = (v) => {
    if (v === undefined || v === null) return '';
    if (typeof v === 'number') return String(v);
    const s = String(v).trim();
    if (!s) return '';
    const m = s.match(/\d+/);
    return m ? m[0] : s;
  };

  const fileName =
    root.file_name ||
    body.file_name ||
    data.file_name ||
    'MTR.pdf';

  if (!fileBase64) {
    throw new Error(`Webhook payload missing file_content_base64. Keys: ${Object.keys(root).join(', ')}`);
  }

  // Simple deterministic hash (no crypto required)
  const hashDjb2 = (str) => {
    let h = 5381;
    for (let i = 0; i < str.length; i++) {
      h = ((h << 5) + h) + str.charCodeAt(i);
      h |= 0;
    }
    return (h >>> 0).toString(16);
  };

  const pdfFingerprint = hashDjb2(fileBase64);

  return {
    json: {
      ...root,
      ...(Object.keys(body).length ? body : {}),
